const $=s=>document.querySelector(s);
const esc=s=>(s||"").replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const uid=()=>Math.random().toString(36).slice(2,9);
const doy=d=>{try{var _p=new URLSearchParams(location.search).get("day");if(_p!==null&&_p!==""&&!isNaN(_p))return parseInt(_p,10);}catch(e){}const s=new Date(d.getFullYear(),0,0);return Math.floor((d-s)/864e5);};
const isoDate=x=>x.getFullYear()+"-"+String(x.getMonth()+1).padStart(2,"0")+"-"+String(x.getDate()).padStart(2,"0");
const greet=()=>{const h=new Date().getHours();return h<12?"Good morning":h<18?"Good afternoon":"Good evening";};
function isoWeek(d){const t=new Date(Date.UTC(d.getFullYear(),d.getMonth(),d.getDate()));const day=t.getUTCDay()||7;t.setUTCDate(t.getUTCDate()+4-day);const ys=new Date(Date.UTC(t.getUTCFullYear(),0,1));return Math.ceil((((t-ys)/864e5)+1)/7);}
function season(d){const m=d.getMonth();return (m<2||m===11)?"Winter":m<5?"Spring":m<8?"Summer":"Autumn";}
function nextSeasonal(d){const today=new Date(d.getFullYear(),d.getMonth(),d.getDate());
  const items=Object.keys(SEASONAL).map(k=>{const p=k.split("-");let dt=new Date(d.getFullYear(),p[0]-1,p[1]);if(dt<today)dt=new Date(d.getFullYear()+1,p[0]-1,p[1]);return {label:SEASONAL[k],dt};});
  items.sort((a,b)=>a.dt-b.dt);return items[0];}
function monthCardHTML(d){
  const y=d.getFullYear(),m=d.getMonth();
  const rt=new Date(), isCur=(rt.getFullYear()===y&&rt.getMonth()===m), today=isCur?rt.getDate():-1;
  const mn=d.toLocaleDateString('en',{month:'long'});
  const first=new Date(y,m,1).getDay(), days=new Date(y,m+1,0).getDate();
  const remMap={};(S.reminders||[]).forEach(r=>{if(!r.date)return;const p=r.date.split("-");if(+p[0]===y&&(+p[1]-1)===m)(remMap[+p[2]]=remMap[+p[2]]||[]).push(r);});
  const bM=S.bday?(+S.bday.split("-")[1]-1):-1, bD=S.bday?(+S.bday.split("-")[2]):0, bdayThis=(bM===m);
  let cells="";["S","M","T","W","T","F","S"].forEach(x=>cells+=`<div class="mc-dow">${x}</div>`);
  for(let i=0;i<first;i++)cells+="<div></div>";
  for(let dd=1;dd<=days;dd++){const key=(m+1)+"-"+dd, mark=SEASONAL[key]||HOLIDAYS[key], rems=remMap[dd], isB=bdayThis&&dd===bD;
    const tip=[mark||"",...(rems?rems.map(r=>'📌 '+r.text):[]),...(isB?['🎂 Your birthday']:[])].filter(Boolean).join(' · ');
    cells+=`<div class="mc-d ${dd===today?'mc-today':''} ${mark?'mc-mark':''} ${rems?'mc-rem':''} ${isB?'mc-bday':''}" title="${esc(tip)}">${dd}${mark?'<span class="mc-dot"></span>':''}${rems?'<span class="mc-rdot"></span>':''}${isB?'<span class="mc-cake">🎂</span>':''}</div>`;}
  const ns=nextSeasonal(rt);
  const tkey=(rt.getMonth()+1)+"-"+rt.getDate(), obs=isCur?(SEASONAL[tkey]||HOLIDAYS[tkey]):null;
  let note=(obs?`✦ Today — <b>${esc(obs)}</b><br>`:"")+`Next seasonal milestone: <b>${esc(ns.label)}</b> · ${ns.dt.toLocaleDateString('en',{month:'long',day:'numeric'})}`;
  if(bdayThis)note+=`<br>🎂 <b>Your birthday</b> — ${new Date(y,m,bD).toLocaleDateString('en',{month:'long',day:'numeric'})}${bD===today?' — today! 🎉':''}`;
  const remList=(S.reminders||[]).filter(r=>{if(!r.date)return false;const p=r.date.split("-");return +p[0]===y&&(+p[1]-1)===m;}).sort((a,b)=>(a.date+(a.time||'')).localeCompare(b.date+(b.time||'')));
  const remHTML=remList.length?`<div class="rule"></div><div class="remcal"><div class="remcal-h">📌 Reminders this month</div>${remList.map(r=>`<div class="remcal-row"><span class="remcal-d">${+r.date.split("-")[2]}</span><span class="remcal-t">${esc(r.text)}${r.time?` · ${esc(r.time)}`:''}</span></div>`).join("")}</div>`:"";
  return `<div class="section-h"><h2>This Month</h2><span class="calnav"><button class="calbtn" onclick="calStep(-1)" aria-label="Previous month">‹</button><small class="note" style="min-width:108px;text-align:center;display:inline-block">${mn} ${y}</small><button class="calbtn" onclick="calStep(1)" aria-label="Next month">›</button></span></div>
    <div class="card cal"><span class="frame"></span><div class="mc-grid">${cells}</div>
      <div class="rule"></div><div class="muted" style="font-size:15px">${note}</div>${remHTML}</div>`;
}
function sunTimes(lat,lng,date){const rad=Math.PI/180,deg=180/Math.PI;
  const day=Math.floor((Date.UTC(date.getFullYear(),date.getMonth(),date.getDate())-Date.UTC(date.getFullYear(),0,0))/864e5);
  function calc(isRise){const lngHour=lng/15,tval=day+((isRise?6:18)-lngHour)/24,M=(0.9856*tval)-3.289;
    let L=M+(1.916*Math.sin(M*rad))+(0.020*Math.sin(2*M*rad))+282.634;L=(L+360)%360;
    let RA=deg*Math.atan(0.91764*Math.tan(L*rad));RA=(RA+360)%360;RA=RA+(Math.floor(L/90)*90-Math.floor(RA/90)*90);RA/=15;
    const sinDec=0.39782*Math.sin(L*rad),cosDec=Math.cos(Math.asin(sinDec));
    const cosH=(Math.cos(90.833*rad)-(sinDec*Math.sin(lat*rad)))/(cosDec*Math.cos(lat*rad));
    if(cosH>1||cosH<-1)return null;let H=isRise?360-deg*Math.acos(cosH):deg*Math.acos(cosH);H/=15;
    let UT=(H+RA-(0.06571*tval)-6.622-lngHour)%24;if(UT<0)UT+=24;return UT;}
  const r=calc(true),s=calc(false);if(r==null||s==null)return null;
  const mk=ut=>{const dt=new Date(Date.UTC(date.getFullYear(),date.getMonth(),date.getDate()));dt.setUTCHours(Math.floor(ut),Math.round((ut%1)*60),0,0);return dt;};
  return {rise:mk(r),set:mk(s)};}
function moonPhase(d){const lp=2551442.8,now=Date.UTC(d.getFullYear(),d.getMonth(),d.getDate(),12)/1000,nm=Date.UTC(2000,0,6,18,14)/1000;
  let p=((now-nm)%lp)/lp;if(p<0)p+=1;const i=Math.floor(p*8+0.5)%8;
  return {name:["New Moon","Waxing Crescent","First Quarter","Waxing Gibbous","Full Moon","Waning Gibbous","Last Quarter","Waning Crescent"][i],emoji:["🌑","🌒","🌓","🌔","🌕","🌖","🌗","🌘"][i]};}
let actx;
function ding(kind){try{actx=actx||new(window.AudioContext||window.webkitAudioContext)();const t=actx.currentTime;
  const mk=(f,s,dur)=>{const o=actx.createOscillator(),g=actx.createGain();o.type="sine";o.frequency.value=f;
    g.gain.setValueAtTime(.0001,t+s);g.gain.exponentialRampToValueAtTime(.2,t+s+.012);
    g.gain.exponentialRampToValueAtTime(.0001,t+s+dur);o.connect(g);g.connect(actx.destination);o.start(t+s);o.stop(t+s+dur+.02);};
  if(kind==="del"){mk(392,0,.3);}else if(kind==="pop"){mk(880,0,.18);mk(660,.12,.2);mk(990,.26,.3);}else{mk(660,0,.16);mk(990,.1,.32);}
}catch(e){}}
function toast(m){const t=$("#toast");t.textContent=m;t.classList.add("show");clearTimeout(t._h);t._h=setTimeout(()=>t.classList.remove("show"),1700);}
async function shareText(txt){const p=txt+"  — via The Living EDIT";
  try{if(navigator.share){await navigator.share({text:p});return;}}catch(e){if(e&&e.name==="AbortError")return;}
  try{await navigator.clipboard.writeText(p);toast("Copied — ready to share!");}catch(e){toast("Copied!");}}
function shareFact(i){const f=FACTS[i];if(f)shareText(f.a);}
function videoUrl(f){return f.v||("https://www.youtube.com/results?search_query="+encodeURIComponent(f.a.slice(0,60)));}
function ytSearch(q){return "https://www.youtube.com/results?search_query="+encodeURIComponent(q);}
function podcastUrl(q){return "https://www.listennotes.com/search/?scope=episode&q="+encodeURIComponent(q);}
