/* ============ READ ALOUD ============ */
let ttsOn=false, ttsKeep=null;
function setReadBtn(on){const b=$('#readBtn');if(b){b.innerHTML=on?'Stop reading':'Read today to me';b.classList.toggle('on',on);}}
function readToday(){
  const synth=window.speechSynthesis;
  if(!synth||typeof SpeechSynthesisUtterance==='undefined'){toast('Voice not supported here');return;}
  if(ttsOn){ttsOn=false;synth.cancel();clearInterval(ttsKeep);setReadBtn(false);return;}
  const d=new Date(), n=doy(d);
  const aff=AFFIRMATIONS[n%AFFIRMATIONS.length], f=FACTS[n%FACTS.length];
  const place=PLACES[n%PLACES.length], animal=ANIMALS[n%ANIMALS.length], plant=PLANTS[n%PLANTS.length];
  const q=QA[n%QA.length], mystery=MYSTERIES[n%MYSTERIES.length];
  const wis=FACTS.map((x,i)=>i).filter(i=>FACTS[i].cat==="wisdom");
  const quote=FACTS[wis.length?wis[n%wis.length]:n%FACTS.length];
  const hist=HIST[(d.getMonth()+1)+"-"+d.getDate()];
  const dateLong=d.toLocaleDateString('en',{weekday:'long',month:'long',day:'numeric'});
  const segs=[];
  segs.push(`${greet()}${S.name?', '+S.name:''}. Here is your Daybook for ${dateLong}.`);
  segs.push(`Today's thought. ${aff}`);
  segs.push(`Fact of the day. ${f.a}${f.d?' '+f.d:''}`);
  if(hist&&hist.length){segs.push('On this day in history.');hist.forEach(h=>segs.push(`In ${h[0]}. ${h[1]}`));}
  segs.push(`Place of the day. ${place.nm}, ${place.country}. ${place.facts.join(' ')}`);
  segs.push(`Animal of the day. ${animal.nm}. ${animal.facts.join(' ')}`);
  segs.push(`Today's plant. ${plant.nm}. ${plant.facts.join(' ')}`);
  segs.push(`A question to ponder. ${q.q} ${q.a}`);
  segs.push(`Words of wisdom. ${quote.a}`);
  segs.push(`And a mystery. ${mystery}`);
  segs.push("That's your Daybook for today. Enjoy the discoveries.");
  synth.cancel();
  ttsOn=true;setReadBtn(true);
  const voices=synth.getVoices()||[];
  const voice=voices.find(v=>/^en/i.test(v.lang)&&v.localService)||voices.find(v=>/^en/i.test(v.lang))||null;
  let i=0;
  (function next(){
    if(!ttsOn)return;
    if(i>=segs.length){ttsOn=false;clearInterval(ttsKeep);setReadBtn(false);return;}
    const u=new SpeechSynthesisUtterance(segs[i++]);
    if(voice){u.voice=voice;u.lang=voice.lang;}else u.lang='en-US';
    u.rate=.96;u.pitch=1;
    u.onend=()=>{if(ttsOn)setTimeout(next,220);};
    u.onerror=()=>{ttsOn=false;clearInterval(ttsKeep);setReadBtn(false);};
    synth.speak(u);
  })();
  clearInterval(ttsKeep);
  ttsKeep=setInterval(()=>{if(ttsOn){try{synth.resume();}catch(e){}}else clearInterval(ttsKeep);},9000);
}

/* ============ CURIOSITY CHALLENGE ============ */
function dailyQuiz(){const n=doy(new Date());const idx=[];let i=0;while(idx.length<Math.min(5,QUIZ.length)){const k=(n*7+i*13)%QUIZ.length;if(idx.indexOf(k)<0)idx.push(k);i++;if(i>300)break;}return idx.map(k=>QUIZ[k]);}
function quizRenderInner(){
  const today=isoDate(new Date());
  if(!QZ.open){
    const best=(S.quiz&&S.quiz.day===today)?S.quiz.best:null;
    const streak=(S.streak&&S.streak.n)?S.streak.n:0;
    return `<div class="label">Curiosity Challenge</div>
      <div class="serif" style="font-size:21px;margin:2px 0 6px">Today's five questions</div>
      <div class="muted ital" style="font-size:13px;margin-bottom:10px">A fresh set each day.${best!=null?` Best today: <b>${best}/5</b>.`:''}${streak>1?` 🔥 ${streak} days in a row.`:''}</div>
      <button class="btn" onclick="quizStart()">Begin the challenge</button>`;
  }
  if(QZ.done){
    const s=QZ.score,n=QZ.qs.length;
    const tier=s===n?'A true almanac-keeper! 🌟':s>=4?'A curious mind! 🦉':s>=3?'Nicely done. 🌿':s>=1?'A fine start. 🌱':"Tomorrow's a fresh page. 📖";
    return `<div class="label">Curiosity Challenge</div>
      <div class="serif" style="font-size:25px;margin:4px 0">${s} / ${n}</div>
      <div class="muted ital" style="margin-bottom:10px">${tier}${(S.streak&&S.streak.n>1)?` · 🔥 ${S.streak.n} days in a row`:''}</div>
      <button class="btn sm" onclick="quizStart()">Play again</button>`;
  }
  const q=QZ.qs[QZ.i];
  return `<div class="label">Curiosity Challenge</div>
    <div class="muted" style="font-size:12px">Question ${QZ.i+1} of ${QZ.qs.length} · Score ${QZ.score}</div>
    <div class="serif" style="font-size:21px;margin:6px 0 10px">${esc(q.q)}</div>
    <div class="quizchoices">${q.c.map((c,ci)=>{let cls='qz';if(QZ.answered){if(ci===q.a)cls+=' right';else if(ci===QZ.pick)cls+=' wrong';else cls+=' dim';}return `<button class="${cls}" ${QZ.answered?'disabled':''} onclick="quizAnswer(${ci})">${esc(c)}</button>`;}).join('')}</div>
    ${QZ.answered?`<div class="muted ital" style="font-size:13px;margin-top:9px">${QZ.pick===q.a?'✅ Correct! ':'❌ Not quite. '}${esc(q.why||'')}</div>
      <div style="margin-top:10px"><button class="btn sm" onclick="quizNext()">${QZ.i+1>=QZ.qs.length?'See result':'Next question'}</button></div>`:''}`;
}
function quizRender(){const b=$('#quizBox');if(b)b.innerHTML=quizRenderInner();}
function quizStart(){QZ={open:true,done:false,i:0,score:0,pick:-1,answered:false,qs:dailyQuiz()};ding();quizRender();}
function quizAnswer(ci){if(QZ.answered)return;QZ.answered=true;QZ.pick=ci;if(ci===QZ.qs[QZ.i].a){QZ.score++;ding('pop');}else ding('del');quizRender();}
function quizNext(){if(QZ.i+1>=QZ.qs.length){quizFinish();}else{QZ.i++;QZ.answered=false;QZ.pick=-1;quizRender();}}
function quizFinish(){QZ.done=true;const today=isoDate(new Date());
  if(!S.quiz||S.quiz.day!==today)S.quiz={day:today,best:QZ.score};else S.quiz.best=Math.max(S.quiz.best,QZ.score);
  const yd=new Date();yd.setDate(yd.getDate()-1);const yest=isoDate(yd);
  if(!S.streak)S.streak={n:0,last:""};
  if(S.streak.last!==today){S.streak.n=(S.streak.last===yest)?S.streak.n+1:1;S.streak.last=today;}
  save();ding('pop');quizRender();}

