function exportData(){try{
  const blob=new Blob([JSON.stringify(S)],{type:"application/json"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");a.href=url;a.download="curio-backup-"+isoDate(new Date())+".json";
  document.body.appendChild(a);a.click();a.remove();
  setTimeout(()=>URL.revokeObjectURL(url),1500);
  ding();toast("Backup downloaded");
}catch(e){toast("Couldn't create the backup");}}
function importData(inp){const f=inp.files&&inp.files[0];if(!f){return;}
  const rd=new FileReader();
  rd.onload=()=>{try{
    const obj=JSON.parse(rd.result);
    if(!obj||typeof obj!=="object")throw 0;
    if(!confirm("Restore from this backup? It will replace your current name, birthday, reminders and notes on this device.")){inp.value="";return;}
    S=Object.assign({name:"",unlocked:false,reminders:[],notes:[],voiceNotes:[],bday:"",quiz:null,streak:null,a11y:null,qOpen:false},obj);
    save();ding("pop");toast("Backup restored");
    applyA11y();
    if('Notification' in window&&Notification.permission==='granted')(S.reminders||[]).forEach(r=>{r.trig=false;scheduleTrigger(r).then(ok=>{if(ok){r.trig=true;save();}});});
    goTab(0);
  }catch(e){toast("That doesn't look like a The Living EDIT backup");}
  inp.value="";};
  rd.onerror=()=>{toast("Couldn't read that file");inp.value="";};
  rd.readAsText(f);}
function drawNotes(){const box=$("#notes");if(!box)return;
  if(!S.notes.length){box.innerHTML=`<div class="center muted ital" style="padding:18px">Your desk is clear — for now.</div>`;return;}
  box.innerHTML=S.notes.slice().reverse().map(nt=>{
    const dt=new Date(nt.ts).toLocaleDateString('en',{month:'short',day:'numeric'});
    const tag={todo:'📋 To-do',note:'📝 Note',thought:'💭 Thought'}[nt.kind]||'📝 Note';
    return `<div class="notecard"><span class="tape"></span>
      <small class="note" style="color:#a8784f">${tag} · ${dt}</small>
      <div class="nt">${esc(nt.text)}</div>
      <div class="nf"><button class="btn ghost sm" onclick="shareNote('${nt.id}')">↗ Share</button>
        <button class="iconbtn" title="Delete" onclick="delNote('${nt.id}')">🗑</button></div>
    </div>`;}).join("");}
function addNote(){const t=$("#noteIn").value.trim();if(!t)return;
  S.notes.push({id:uid(),text:t,kind:orgTab,ts:Date.now()});save();ding();toast("Note saved");$("#noteIn").value="";drawNotes();stopMic();}
function delNote(id){S.notes=S.notes.filter(n=>n.id!==id);save();ding("del");toast("Note deleted");drawNotes();}
function noteById(id){return (S.notes.find(n=>n.id===id)||{}).text||"";}
function shareNote(id){shareText(noteById(id));}
let mediaRec=null,recOn=false,recChunks=[],curAudio=null;
function toggleMic(){recOn?stopMic():startMic();}
function startMic(){
  if(!navigator.mediaDevices||!window.MediaRecorder){$("#micNote").textContent="Voice recording isn't supported here — try Chrome.";return;}
  navigator.mediaDevices.getUserMedia({audio:true}).then(stream=>{
    recChunks=[];try{mediaRec=new MediaRecorder(stream);}catch(e){try{mediaRec=new MediaRecorder(stream,{mimeType:'audio/webm'});}catch(e2){$("#micNote").textContent="Recording isn't supported here.";return;}}
    mediaRec.ondataavailable=e=>{if(e.data&&e.data.size)recChunks.push(e.data);};
    mediaRec.onstop=()=>{stream.getTracks().forEach(t=>t.stop());
      const blob=new Blob(recChunks,{type:(mediaRec&&mediaRec.mimeType)||'audio/webm'});
      const rd=new FileReader();rd.onload=()=>{if(!S.voiceNotes)S.voiceNotes=[];S.voiceNotes.push({id:uid(),audio:rd.result,ts:Date.now()});save();drawVoiceNotes();ding();toast("Voice note saved");$("#micNote").textContent="";};rd.readAsDataURL(blob);};
    mediaRec.start();recOn=true;const b=$("#micBtn");if(b){b.classList.add("rec");b.innerHTML="● Stop recording";}$("#micNote").textContent="Recording… tap to stop.";
  }).catch(()=>{$("#micNote").textContent="Couldn't access the microphone — check permission.";});}
function stopMic(){if(mediaRec&&recOn){try{mediaRec.stop();}catch(e){}}recOn=false;const b=$("#micBtn");if(b){b.classList.remove("rec");b.innerHTML="🎙 Voice note";}}
function drawVoiceNotes(){const box=$("#voiceList");if(!box)return;const vs=(S.voiceNotes||[]);
  box.innerHTML=vs.length?vs.slice().reverse().map(v=>{const dt=new Date(v.ts);const lbl=dt.toLocaleDateString('en',{month:'short',day:'numeric'})+' · '+dt.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});
    return `<div class="vnote"><span class="vlabel">🎙 ${lbl}</span><span class="vbtns"><button class="btn sm" onclick="playVoice('${v.id}')">▶ Play</button><button class="iconbtn" title="Delete" onclick="delVoice('${v.id}')">🗑</button></span></div>`;}).join(""):"";}
function playVoice(id){const v=(S.voiceNotes||[]).find(x=>x.id===id);if(!v)return;try{if(curAudio)curAudio.pause();curAudio=new Audio(v.audio);curAudio.play().catch(()=>toast("Couldn't play recording"));}catch(e){toast("Couldn't play recording");}}
function delVoice(id){S.voiceNotes=(S.voiceNotes||[]).filter(x=>x.id!==id);save();ding("del");toast("Voice note deleted");drawVoiceNotes();}

/* ============ TABS ============ */
function toggleMenu(){const m=$("#menu"),open=!m.classList.contains("open");m.classList.toggle("open",open);$("#menuScrim").classList.toggle("show",open);$("#hamb").classList.toggle("x",open);}
function applyA11y(){const a=S.a11y||{};const v=$('#view');if(v)v.style.zoom=a.text==='large'?'1.18':a.text==='xlarge'?'1.34':'';document.body.classList.toggle('a11y-contrast',!!a.contrast);}
function a11yBody(){const a=S.a11y||{text:'normal',contrast:false};
  return `<div class="serif" style="font-size:25px;margin-bottom:2px">Accessibility</div>
    <div class="muted ital" style="font-size:13px;margin-bottom:6px">Make The Living EDIT easier to read and use. Your choices are saved on this device.</div>
    <div class="a11y-row"><div class="lab">Text size</div>
      <div class="a11y-seg">
        <button class="${(!a.text||a.text==='normal')?'on':''}" onclick="setA11yText('normal')">Normal</button>
        <button class="${a.text==='large'?'on':''}" onclick="setA11yText('large')">Large</button>
        <button class="${a.text==='xlarge'?'on':''}" onclick="setA11yText('xlarge')">Larger</button>
      </div>
      <div class="hint">Scales the whole page up for easier reading.</div>
    </div>
    <div class="a11y-row"><div class="lab">High contrast</div>
      <div class="hint" style="margin-bottom:8px">Darkens faint text and strengthens outlines.</div>
      <button class="toggle ${a.contrast?'on':''}" onclick="toggleA11yContrast()">${a.contrast?'On':'Off'}</button>
    </div>
    <div class="center" style="margin-top:16px"><button class="btn" onclick="closeA11y()">Done</button></div>`;
}
function openA11y(){closeMenu();$('#a11yBody').innerHTML=a11yBody();$('#a11ySheet').classList.add('show');}
function closeA11y(){$('#a11ySheet').classList.remove('show');}
function setA11yText(v){if(!S.a11y)S.a11y={text:'normal',contrast:false};S.a11y.text=v;save();applyA11y();$('#a11yBody').innerHTML=a11yBody();ding();}
function toggleA11yContrast(){if(!S.a11y)S.a11y={text:'normal',contrast:false};S.a11y.contrast=!S.a11y.contrast;save();applyA11y();$('#a11yBody').innerHTML=a11yBody();ding();}
function closeMenu(){$("#menu").classList.remove("open");$("#menuScrim").classList.remove("show");$("#hamb").classList.remove("x");}
function goTab(n){closeMenu(); if(typeof S!=="undefined" && !S.unlocked && (n===1||n===3||n===5)){ openBilling(); return; } setTab(n);}
function setTab(n){ try{setLoc(tabName(n));}catch(e){} try{setBotnav(n);}catch(e){} try{breathFx();}catch(e){}
  if(n!==2)stopMic();
  tab=n;almStack=[];
  ["mi0","mi1","mi2"].forEach((id,i)=>{const el=$("#"+id);if(el)el.classList.toggle("on",i===n);});
  var _mn=document.getElementById("miNest");if(_mn)_mn.classList.toggle("on",n===3);
  var _mh=document.getElementById("miHowTo");if(_mh)_mh.classList.toggle("on",n===4);
  const v=$("#view");
  if(n===0){calOffset=0;v.innerHTML=renderHome();drawReminders();tickClock();celebrateBdayMaybe();setReadBtn(ttsOn);}
  else if(n===1){v.innerHTML=renderAlmanac();drawRH();}
  else if(n===3){v.innerHTML=renderNest();}
  else if(n===4){v.innerHTML=renderHowTo();}
  else if(n===5){v.innerHTML=renderSaved();}
  else {v.innerHTML=renderOrganizer();if(S.unlocked){drawNotes();drawVoiceNotes();}}
  window.scrollTo({top:0,behavior:"smooth"});
}
applyA11y();
checkReminders();
if('serviceWorker' in navigator){try{navigator.serviceWorker.register('sw.js').catch(()=>{});}catch(e){}}

(function(){
  function applyDayNight(){var night=(typeof nightWanted==="function")?nightWanted():((new Date().getHours()>=18)||(new Date().getHours()<6));
    document.body.classList.toggle("night",night);
    var mt=document.querySelector('meta[name=theme-color]');if(mt)mt.setAttribute('content',night?'#0e1830':'#f1e7d2');}
  applyDayNight();
  setInterval(applyDayNight,60000);
})();

