/* The Living EDIT — 7-day free trial of The Living EDIT+. Additive: uses existing S / save() / setTab() / toast(). */
var CURIO_TRIAL_MS = 7*24*60*60*1000;
function curioTrialActive(){ return typeof S!=='undefined' && S.trialStart>0 && (Date.now()-S.trialStart) < CURIO_TRIAL_MS; }
function curioTrialDaysLeft(){ if(!curioTrialActive()) return 0; return Math.max(1, Math.ceil((CURIO_TRIAL_MS-(Date.now()-S.trialStart))/86400000)); }
function curioTrialSync(){
  if(typeof S==='undefined') return;
  if(S.paid){ if(!S.unlocked){ S.unlocked=true; if(typeof save==='function') save(); } return; }
  if(S.trialStart>0){
    if(curioTrialActive()){ if(!S.unlocked){ S.unlocked=true; if(typeof save==='function') save(); } }
    else if(S.unlocked){ S.unlocked=false; if(typeof save==='function') save(); }
  }
}
function startTrial(){
  if(typeof S==='undefined') return;
  if(S.paid) return;
  if(S.trialStart>0){ if(typeof toast==='function') toast('Your free trial has already been used'); return; }
  S.trialStart=Date.now(); S.unlocked=true; if(typeof save==='function') save();
  try{ if(typeof ding==='function') ding(); }catch(e){}
  if(typeof toast==='function') toast('Your 7-day trial has begun \u2014 enjoy all of The Living EDIT+ \u2726');
  try{ if(typeof setTab==='function') setTab(typeof tab!=='undefined'?tab:0); }catch(e){}
}
function curioInjectTrial(){
  var v=document.getElementById('view'); if(!v) return;
  if(v.querySelector('.curio-trial-btn,.curio-trial-note')) return;   /* one CTA per view */
  var btn=v.querySelector('button[onclick="subscribe()"]'); if(!btn || !btn.parentNode) return; if(btn.classList.contains("home-explore")) return;
  if(typeof S==='undefined' || S.paid) return;
  if(curioTrialActive()){
    var d=curioTrialDaysLeft();
    var note=document.createElement('div'); note.className='curio-trial-note';
    note.textContent='\u2726 Free trial active \u2014 '+d+' day'+(d===1?'':'s')+' left';
    btn.parentNode.insertBefore(note, btn); return;
  }
  if(S.trialStart>0){
    var n2=document.createElement('div'); n2.className='curio-trial-note';
    n2.textContent='Your free trial has ended.';
    btn.parentNode.insertBefore(n2, btn); return;
  }
  var tb=document.createElement('button');
  tb.className='btn curio-trial-btn'; tb.type='button';
  tb.textContent='Start your 7-day free trial';
  tb.onclick=function(ev){ ev.preventDefault(); ev.stopPropagation(); startTrial(); };
  btn.parentNode.insertBefore(tb, btn);
}
