/* ============ A11y: keyboard support for div/span click controls ============ */
(function(){
  function enhance(){
    var els=document.querySelectorAll('.chip,.back,.qotd');
    for(var i=0;i<els.length;i++){
      var el=els[i];
      if(!el.hasAttribute('role')) el.setAttribute('role','button');
      if(!el.hasAttribute('tabindex')) el.setAttribute('tabindex','0');
    }
  }
  // Enter / Space activate any non-native button control.
  document.addEventListener('keydown',function(e){
    if(e.key!=='Enter'&&e.key!==' ') return;
    var t=e.target;
    if(t&&t.getAttribute&&t.getAttribute('role')==='button'&&t.tagName!=='BUTTON'){
      e.preventDefault(); t.click();
    }
  });
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',enhance); else enhance();
  // Re-run as views re-render into #view.
  var v=document.getElementById('view');
  if(v){ onViewChange(enhance); }
})();


/* Water-droplet sound + Daily Drop reveal */
function bloop(){try{actx=actx||new(window.AudioContext||window.webkitAudioContext)();const t=actx.currentTime;
  const o=actx.createOscillator(),g=actx.createGain();o.type="sine";
  o.frequency.setValueAtTime(820,t);o.frequency.exponentialRampToValueAtTime(280,t+.18);
  g.gain.setValueAtTime(.0001,t);g.gain.exponentialRampToValueAtTime(.28,t+.01);
  g.gain.exponentialRampToValueAtTime(.0001,t+.32);
  o.connect(g);g.connect(actx.destination);o.start(t);o.stop(t+.34);}catch(e){}}
