/* ===== A Quiet Minute — guided breathing ===== */
var breathOn=false, breathStart=0;
function setBreathText(t){ var e=document.getElementById("breathText"); if(e)e.textContent=t; }
function toggleBreath(){
  var c=document.getElementById("breathCircle"), b=document.getElementById("breathBtn");
  if(breathOn){ breathOn=false; if(c)c.classList.remove("breathing"); if(b)b.textContent="Begin a minute"; setBreathText("Breathe"); breathRing(289); stopRain(); return; }
  breathOn=true; breathStart=Date.now(); breathRing(289); try{ding();}catch(e){}
  if(c)c.classList.add("breathing"); if(b)b.textContent="Stop"; if(breathSound) startRain();
  breathTick();
}
function breathTick(){
  if(!breathOn) return;
  var el=Date.now()-breathStart;
  if(el>=60000){ breathOn=false; var c=document.getElementById("breathCircle"), b=document.getElementById("breathBtn");
    if(c)c.classList.remove("breathing"); if(b)b.textContent="Begin a minute"; breathRing(0); stopRain(); setBreathText("Well done \u2726"); try{ding("pop");}catch(e){} return; }
  breathRing(289*(1-el/60000)); var p=el%10000;
  setBreathText(p<4000?"Breathe in":(p<6000?"Hold":"Breathe out"));
  setTimeout(breathTick,250);
}

function breathRing(o){ var r=document.getElementById("breathRing"); if(r) r.style.strokeDashoffset=o; }


/* ===== Rain ambience (synth, no asset) ===== */
var rainSrc=null, rainGain=null, breathSound=true;
function startRain(){ try{ actx=actx||new(window.AudioContext||window.webkitAudioContext)(); if(rainSrc) return;
  var n=2*actx.sampleRate, buf=actx.createBuffer(1,n,actx.sampleRate), d=buf.getChannelData(0), last=0;
  for(var i=0;i<n;i++){ var w=Math.random()*2-1; last=(last+0.02*w)/1.02; d[i]=last*3.4; }
  var src=actx.createBufferSource(); src.buffer=buf; src.loop=true;
  var lp=actx.createBiquadFilter(); lp.type="lowpass"; lp.frequency.value=1100;
  var hp=actx.createBiquadFilter(); hp.type="highpass"; hp.frequency.value=420;
  rainGain=actx.createGain(); rainGain.gain.value=0.0001;
  src.connect(hp); hp.connect(lp); lp.connect(rainGain); rainGain.connect(actx.destination); src.start(0);
  rainGain.gain.exponentialRampToValueAtTime(0.10, actx.currentTime+1.6); rainSrc=src;
}catch(e){} }
function stopRain(){ try{ if(rainGain&&actx){ rainGain.gain.exponentialRampToValueAtTime(0.0001, actx.currentTime+0.7); }
  var sx=rainSrc; rainSrc=null; rainGain=null; if(sx) setTimeout(function(){ try{sx.stop();}catch(e){} },800); }catch(e){} }
function toggleBreathSound(){ breathSound=!breathSound; var b=document.getElementById("soundBtn"); if(b)b.textContent="Rain: "+(breathSound?"on":"off");
  if(typeof breathOn!=="undefined"&&breathOn){ if(breathSound) startRain(); else stopRain(); } }

/* ===== Adaptive background by time of day ===== */
function applyTimeTheme(){ try{ var g;
  if(typeof nightWanted==="function" && nightWanted()){ g="linear-gradient(180deg,#141a2b 0%,#0b1019 100%)"; }
  else { var h=new Date().getHours();
    if(h>=5&&h<11) g="linear-gradient(180deg,#FCEFD6 0%,#F6E5C7 100%)";
    else if(h>=11&&h<17) g="linear-gradient(180deg,#F7F1E6 0%,#EFE7D6 100%)";
    else if(h>=17&&h<21) g="linear-gradient(180deg,#DEE0EA 0%,#C6CBDD 100%)";
    else g="linear-gradient(180deg,#D2D5E2 0%,#BAC0D4 100%)"; }
  document.documentElement.style.setProperty("--page-bg", g);
}catch(e){} }

/* ===== Theme preference: Auto (by time) / Light / Dark ===== */
function nightWanted(){ var t=(typeof S!=="undefined" && S && S.theme)||"auto"; if(t==="dark")return true; if(t==="light")return false; var h=new Date().getHours(); return (h>=18||h<6); }
function applyThemeNow(){ try{ var night=nightWanted(); document.body.classList.toggle("night",night);
  var mt=document.querySelector('meta[name=theme-color]'); if(mt)mt.setAttribute('content',night?'#0e1830':'#f1e7d2');
  applyTimeTheme(); }catch(e){} }
function setTheme(v){ if(typeof S!=="undefined" && S){ S.theme=v; try{save();}catch(e){} } applyThemeNow(); try{ding();}catch(e){}
  if(typeof toast==="function") toast(v==="auto"?"Theme follows the time of day":(v==="dark"?"Dark theme on":"Light theme on"));
  var box=document.getElementById("themeSeg"); if(box){ var b=box.querySelectorAll("button"); for(var i=0;i<b.length;i++){ b[i].classList.toggle("on", b[i].getAttribute("data-th")===v); } } }

/* ===== Breathe-with-me transition on screen switch ===== */
function breathFx(){ var el=document.getElementById("breathFx"); if(!el) return; el.classList.remove("go"); void el.offsetWidth; el.classList.add("go"); setTimeout(function(){ if(el)el.classList.remove("go"); },700); }

try{ applyTimeTheme(); setInterval(applyTimeTheme, 300000); }catch(e){}


/* ===== Billing: Google Play (Digital Goods API) with browser fallback ===== */
var PLAY_BILLING="https://play.google.com/billing";
var PLANS={
  yearly:{ id:"livingedityearly", label:"Yearly" },
  monthly:{ id:"livingeditmonthly", label:"Monthly" }
};
function billingService(){
  return new Promise(function(resolve){
    try{ if(window.getDigitalGoodsService){ window.getDigitalGoodsService(PLAY_BILLING).then(resolve).catch(function(){resolve(null);}); return; } }catch(e){}
    resolve(null);
  });
}
function openPlanChooser(){
  var html='<h2 class="serif" style="font-size:25px;margin:0 0 6px">The Living EDIT+</h2>'+
    '<div class="muted ital" style="margin-bottom:16px">Unlimited facts, every topic, your Saved page, and the calm extras.</div>'+
    '<div class="inrow" style="flex-direction:column;gap:10px;align-items:stretch">'+
      '<button class="btn" onclick="buyPlan(\'yearly\')">Yearly &mdash; best value</button>'+
      '<button class="btn ghost" onclick="buyPlan(\'monthly\')">Monthly</button>'+
    '</div>'+
    '<div class="muted ital" style="font-size:13px;margin-top:14px">Start with a 7-day free trial, then it renews automatically. Cancel anytime in Google Play.</div>';
  if(typeof openAppSheet==="function") openAppSheet(html); else { grantPremium(); }
}
function buyPlan(which){
  var plan=PLANS[which]; if(!plan) return;
  try{ S.paidSku=plan.id; }catch(e){}
  billingService().then(function(svc){
    if(!svc || typeof PaymentRequest==="undefined"){ if(typeof closeAppSheet==="function") closeAppSheet(); grantPremium(); return; } /* browser/dev fallback */
    try{
      var pr=new PaymentRequest(
        [{ supportedMethods:PLAY_BILLING, data:{ sku:plan.id } }],
        { total:{ label:"The Living EDIT+", amount:{ currency:"USD", value:"0" } } });
      pr.show().then(function(resp){
        var token=resp.details && (resp.details.purchaseToken||resp.details.token);
        resp.complete("success").then(function(){
          try{ if(svc.acknowledge && token) svc.acknowledge(token); }catch(e){}
          if(typeof closeAppSheet==="function") closeAppSheet(); grantPremium();
        });
      }).catch(function(){ /* user cancelled */ });
    }catch(e){ /* ignore */ }
  });
}
function grantPremium(){
  S.premium=true; S.unlocked=true; S.paid=true;
  try{ localStorage.setItem("le_playowner","1"); }catch(e){}   /* this device owns the Play purchase */
  save();
  try{ if(window.__cloudReady && typeof cloudPush==="function") cloudPush(); }catch(e){}  /* attach membership to the signed-in account */
  try{ding("pop");}catch(e){}
  toast("Welcome to The Living EDIT+ ✦");
  setTab(typeof tab!=="undefined"?tab:0);
}
/* Reconcile Google Play with the account. Called after sign-in/sync (see cloud.js).
   Membership follows the email account; Google Play is used to grant it and to
   revoke it on the device that actually owns the subscription. */
function checkBillingEntitlement(){
  billingService().then(function(svc){
    if(!svc || !svc.listPurchases) return;                 /* can't verify (browser/offline) -> leave state as-is */
    svc.listPurchases().then(function(purchases){
      var active=purchases && purchases.some(function(p){ return p.itemId===PLANS.monthly.id || p.itemId===PLANS.yearly.id; });
      var owner=false; try{ owner=localStorage.getItem("le_playowner")==="1"; }catch(e){}
      if(active){
        try{ localStorage.setItem("le_playowner","1"); }catch(e){}
        if(!S.premium || !S.unlocked){ S.premium=true; S.unlocked=true; save(); try{ if(window.__cloudReady && typeof cloudPush==="function") cloudPush(); }catch(e){} if(typeof tab!=="undefined") setTab(tab); }
      } else if(owner){
        /* this device owned the subscription and Google now reports it inactive -> revoke */
        if(S.premium || S.unlocked){ S.premium=false; S.unlocked=false; save(); try{ if(window.__cloudReady && typeof cloudPush==="function") cloudPush(); }catch(e){} if(typeof tab!=="undefined") setTab(tab); }
      }
    }).catch(function(){});
  });
}
/* Model A: entitlement is the device's Google Play purchase — check it on every launch. */
try{ checkBillingEntitlement(); }catch(e){}
